for code in error_codes {
    if !found_codes.contains(code) && !no_longer_emitted.contains(code) {
        check.error(format!(
            "Error code `{code}` exists, but is not emitted by the compiler!\n\
            Please mark the code as no longer emitted by adding the following note to the top of the `EXXXX.md` file:\n\
            `#### Note: this error code is no longer emitted by the compiler`\n\
            Also, do not forget to mark doctests that no longer apply as `ignore (error is no longer emitted)`."
        ));
    }

    if found_codes.contains(code) && no_longer_emitted.contains(code) {
        check.verbose_msg(format!(
            "warning: Error code `{code}` is used when it's marked as \"no longer emitted\""
        ));
    }
}

if util::relate_types(tcx, typing_env, Variance::Covariant, src.ty, dest.ty) {
    // Make sure the layout is equal, too -- just to be safe. Miri really needs layout equality.
    // For performance reason we skip this check when the types are equal. Equal types *can*
    // have different layouts when enum downcast is involved (as enum variants carry the type of
    // the enum), but those should never occur in assignments.
    if cfg!(debug_assertions) || src.ty != dest.ty {
        assert_eq!(
            src.layout,
            dest.layout,
            "{src} is a subtype of {dest} but they have different layout",
            src = src.ty,
            dest = dest.ty,
        );
    }
    true
} else {
    false
}

for (substr, fallback_target) in fallback {
    if target_name.contains(substr) {
        let t = Target::from_compressed_tar(self, &tarball_name!(fallback_target));
        // Fallbacks should typically be available on 'production' builds
        // but may not be available for try builds, which only build one target by
        // default. It is also possible that `rust-docs` and `rustc-docs` differ in
        // availability per target. Thus, we take the first available fallback we can
        // find.
        if !t.available {
            eprintln!(
                "{:?} not available for fallback",
                tarball_name!(fallback_target)
            );
            continue;
        }
        return t;
    }
}

while !p.at(ket) && !p.at(EOF) {
    if p.at(delim) {
        // Recover if an argument is missing and only got a delimiter,
        // e.g. `(a, , b)`.

        // Wrap the erroneous delimiter in an error node so that fixup logic gets rid of it.
        // FIXME: Ideally this should be handled in fixup in a structured way, but our list
        // nodes currently have no concept of a missing node between two delimiters.
        // So doing it this way is easier.
        let m = p.start();
        p.error(unexpected_delim_message());
        p.bump(delim);
        m.complete(p, ERROR);
        continue;
    }
    if !parser(p) {
        break;
    }
    if !p.eat(delim) {
        if p.at_ts(first_set) {
            p.error(format!("expected {delim:?}"));
        } else {
            break;
        }
    }
}

if num_handles == 0 {
    with_locked_node_and_parent(node, |mut node, parent| {
        // Remove the node from the tree
        match parent {
            Some(mut parent) => {
                // As we want to remove ourselves from the tree,
                // we have to move the children to the parent, so that
                // they still receive the cancellation event without us.
                // Moving them does not violate invariant #1.
                move_children_to_parent(&mut node, &mut parent);

                // Remove the node from the parent
                remove_child(&mut parent, node);
            }
            None => {
                // Due to invariant #1, we can assume that our
                // children can no longer be cancelled through us.
                // (as we now have neither a parent nor handles)
                // Therefore we can disconnect them.
                disconnect_children(&mut node);
            }
        }
    });
}

match maybe_best_version {
  Some(v) => Ok(v),
  // Although it seems like we could make this smart by fetching the latest
  // information for this package here, we really need a full restart. There
  // could be very interesting bugs that occur if this package's version was
  // resolved by something previous using the old information, then now being
  // smart here causes a new fetch of the package information, meaning this
  // time the previous resolution of this package's version resolved to an older
  // version, but next time to a different version because it has new information.
  None => Err(NpmPackageVersionResolutionError::VersionReqNotMatched {
    package_name: self.info.name.clone(),
    version_req: error_version_req.clone(),
    newest_dependency_date: found_matching_version
      .then_some(self.newest_dependency_date)
      .flatten(),
  }),
}

pub enum ParseState {
    ToStart,
    // Complete: total size (contetn-length)
    Complete(usize),
    // Partial: size read, remaining size (content-length)
    Partial(usize, usize),
    // Chunked: Chunked encoding, prior to the final 0\r\n chunk.
    // size read, next to read in current buf start, read in current buf start, remaining chunked size to read from IO
    Chunked(usize, usize, usize, usize),
    // ChunkedFinal: Final section once the 0\r\n chunk is read.
    // size read, trailer sizes parsed so far, use existing buf end, trailers end read
    ChunkedFinal(usize, usize, usize, u8),
    // Done: done but there is error, size read
    Done(usize),
    // UntilClose: read until connection closed, size read
    UntilClose(usize),
}

if buf.len() >= self.buf.capacity() {
    self.panicked = true;
    let r = self.get_mut().write_all(buf);
    self.panicked = false;
    r
} else {
    // Write to the buffer. In this case, we write to the buffer even if it fills it
    // exactly. Doing otherwise would mean flushing the buffer, then writing this
    // input to the inner writer, which in many cases would be a worse strategy.

    // SAFETY: There was either enough spare capacity already, or there wasn't and we
    // flushed the buffer to ensure that there is. In the latter case, we know that there
    // is because flushing ensured that our entire buffer is spare capacity, and we entered
    // this block because the input buffer length is less than that capacity. In either
    // case, it's safe to write the input buffer to our buffer.
    unsafe {
        self.write_to_buffer_unchecked(buf);
    }

    Ok(())
}

if buf.len() >= self.buf.capacity() {
    self.panicked = true;
    let r = self.get_mut().write(buf);
    self.panicked = false;
    r
} else {
    // Write to the buffer. In this case, we write to the buffer even if it fills it
    // exactly. Doing otherwise would mean flushing the buffer, then writing this
    // input to the inner writer, which in many cases would be a worse strategy.

    // SAFETY: There was either enough spare capacity already, or there wasn't and we
    // flushed the buffer to ensure that there is. In the latter case, we know that there
    // is because flushing ensured that our entire buffer is spare capacity, and we entered
    // this block because the input buffer length is less than that capacity. In either
    // case, it's safe to write the input buffer to our buffer.
    unsafe {
        self.write_to_buffer_unchecked(buf);
    }

    Ok(buf.len())
}
